from collections import defaultdict, deque
import ag2

def tool_loop_detector(conversation):
    tool_history = defaultdict(lambda: deque(maxlen=10))

    for msg in conversation.messages:
        if msg.get('tool_calls'):
            for tool_call in msg['tool_calls']:
                tool_id = f"{tool_call['name']}:{tool_call['args']}"
                tool_history[tool_id].append(msg)

                if len(tool_history[tool_id]) >= 5:
                    recent_calls = list(tool_history[tool_id])
                    time_window = recent_calls[-1].timestamp - recent_calls[0].timestamp
                    if time_window < 300:  # 5min window
                        return {
                            'loop_detected': True,
                            'tool': tool_call['name'],
                            'count': len(tool_history[tool_id]),
                            'agents_involved': len(set(m.agent_id for m in recent_calls))
                        }
    return {'loop_detected': False}

import hashlib
from ag2 import GroupChat

def semantic_tool_loop_detector(group_chat: GroupChat):
    tool_patterns = {}

    for turn in group_chat.chat_history[-20:]:  # last 20 turns
        speaker = turn.speaker
        if hasattr(turn, 'tool_calls') and turn.tool_calls:
            for tool_call in turn.tool_calls:
                # Hash tool name + args for semantic comparison
                arg_str = str(sorted(tool_call.args.items()))
                pattern_hash = hashlib.md5(f"{tool_call.name}:{arg_str}".encode()).hexdigest()

                if pattern_hash not in tool_patterns:
                    tool_patterns[pattern_hash] = {'count': 0, 'agents': set()}

                tool_patterns[pattern_hash]['count'] += 1
                tool_patterns[pattern_hash]['agents'].add(speaker.agent_id)

                if tool_patterns[pattern_hash]['count'] >= 4 and len(tool_patterns[pattern_hash]['agents']) >= 2:
                    return {
                        'loop_detected': True,
                        'pattern_hash': pattern_hash,
                        'tool_name': tool_call.name,
                        'agent_diversity': len(tool_patterns[pattern_hash]['agents'])
                    }
    return {'loop_detected': False}

from difflib import SequenceMatcher
import ag2.types as ag_types

def output_convergence_detector(messages: list[ag_types.Message]):
    tool_outputs = []

    for msg in messages[-15:]:
        if hasattr(msg, 'tool_results') and msg.tool_results:
            for result in msg.tool_results:
                tool_outputs.append({
                    'content': result.content,
                    'agent': msg.agent_id,
                    'timestamp': msg.timestamp
                })

    if len(tool_outputs) < 3:
        return {'loop_detected': False}

    # Check last 3 outputs for >95% similarity
    recent = tool_outputs[-3:]
    similarity = SequenceMatcher(None, recent[0]['content'], recent[-1]['content']).ratio()

    if similarity > 0.95:
        return {
            'loop_detected': True,
            'similarity_score': similarity,
            'identical_outputs': len(recent),
            'agents': len(set(r['agent'] for r in recent))
        }

    return {'loop_detected': False}

