from ag2 import register_message_hook
import time
from typing import Dict, Any

class ToolCooldownManager:
    def __init__(self):
        self.cooldowns: Dict[str, float] = {}
        self.last_call: Dict[str, float] = {}

    def check_cooldown(self, tool_signature: str, cooldown_secs: int = 60) -> bool:
        now = time.time()
        if tool_signature in self.last_call:
            if now - self.last_call[tool_signature] < cooldown_secs:
                return False
        self.last_call[tool_signature] = now
        return True

cooldown_mgr = ToolCooldownManager()

def cooldown_hook(message):
    if message.get('tool_calls'):
        for tool_call in message['tool_calls']:
            signature = f"{tool_call['name']}:{str(sorted(tool_call['args'].items()))}"
            if not cooldown_mgr.check_cooldown(signature):
                message['tool_calls'] = []  # Block redundant call
                message['content'] += "\n[Tool on cooldown - using cached result]"
    return message

register_message_hook(cooldown_hook)

from ag2 import GroupChatManager
import json
from datetime import datetime, timedelta

class SharedToolCache:
    def __init__(self):
        self.cache = {}  # tool_signature -> {'result': data, 'expires': timestamp}

    def get(self, tool_signature: str) -> dict | None:
        if tool_signature in self.cache:
            if datetime.now() < self.cache[tool_signature]['expires']:
                return self.cache[tool_signature]['result']
            del self.cache[tool_signature]
        return None

    def set(self, tool_signature: str, result: dict, ttl_minutes: int = 10):
        expires = datetime.now() + timedelta(minutes=ttl_minutes)
        self.cache[tool_signature] = {'result': result, 'expires': expires}

shared_cache = SharedToolCache()

def cache_tool_calls(agent):
    original_execute = agent.execute_tool

    def cached_execute(tool_name, tool_args):
        signature = f"{tool_name}:{json.dumps(tool_args, sort_keys=True)}"
        cached = shared_cache.get(signature)
        if cached:
            return cached
        result = original_execute(tool_name, tool_args)
        shared_cache.set(signature, result)
        return result

    agent.execute_tool = cached_execute
    return agent

from ag2 import GroupChat, register_groupchat_hook

class LoopBreaker:
    def __init__(self):
        self.tool_call_counts = defaultdict(int)
        self.last_tool_users = set()

    def detect_loop(self, chat_history):
        recent_tools = [m for m in chat_history[-10:] if m.get('tool_calls')]
        if len(recent_tools) >= 5 and len({m.agent_id for m in recent_tools}) <= 2:
            return True
        return False

    def break_loop(self, group_chat: GroupChat):
        # Force select agent who hasn't used tools recently
        non_tool_agents = set(group_chat.agents) - self.last_tool_users
        if non_tool_agents:
            next_speaker = non_tool_agents.pop()
            group_chat.override_speaker(next_speaker)
            return True
        return False

def loop_breaker_hook(group_chat: GroupChat, proposed_speaker):
