    if breaker.detect_loop(group_chat.chat_history):
        if breaker.break_loop(group_chat):
            return {'interrupted': True, 'reason': 'tool_loop_detected'}
    return {'interrupted': False}

register_groupchat_hook(loop_breaker_hook)
